pragma solidity ^0.8.20;

contract PresaleMint {
    address private immutable owner;
    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState = State.PresaleLive;

    mapping(address => bool) public presalerList;
    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;

    event WhitelistUpdated(address user, bool status);
    event SaleStateChanged(State newState);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    modifier validTransition(State newState) {
        require(newState != currentState, "Invalid state transition");
        require(
            (currentState == State.PresaleLive && newState == State.SaleLive) ||
            (currentState == State.SaleLive && newState == State.SaleClosed) ||
            (currentState == State.SaleClosed && newState == State.PresaleLive),
            "Invalid state transition"
        );
        _;
    }

    function toggleSale(State newState) public onlyOwner validTransition(newState) {
        currentState = newState;
        emit SaleStateChanged(newState);
    }

    function whitelist(address user, bool status) public onlyOwner {
        presalerList[user] = status;
        emit WhitelistUpdated(user, status);
    }

    function presaleBuy(uint256 amount) public payable {
        require(currentState == State.PresaleLive, "Presale is not live");
        require(presalerList[msg.sender], "Not whitelisted");
        require(amount > 0, "Amount must be greater than zero");
        unchecked {
            require(amount + presaleAmountMinted <= maxPresaleAmount, "Exceeds presale limit");
            presaleAmountMinted += amount;
        }
    }

    function buy(uint256 amount) public payable {
        require(currentState == State.SaleLive, "Public sale is not live");
        require(amount > 0, "Amount must be greater than zero");
        unchecked {
            require(amount + publicAmountMinted <= maxPublicAmount, "Exceeds public limit");
            publicAmountMinted += amount;
        }
    }

    // Constants for maximum mintable amounts (to be defined)
    uint256 public constant maxPresaleAmount = 1000; // Example value
    uint256 public constant maxPublicAmount = 1000; // Example value
}
